// Finalization registry for GLibDate
const glibdateRegistry = new FinalizationRegistry((ptr: string) => {
  fetch(apiConfig.fullBaseUrl + '/GLib/Date/ptr,' + ptr + '/free')
    .catch(err => console.error('Failed to free GLibDate:', ptr, err));
});

